TRANSLATIONS: dict[int, dict] = {
251: {"nativeDefinition": "To be cautious rather than take risks.", "japaneseMeaning": "慎重策を取る", "etymology": "err on the side of caution（慎重の側に傾く）で、安全側に倒すことを表す。", "examples": {"B": "サンタの存在を子どもに聞くのは親だけにすべきだと思う。慎重策を取るべきだ。", "C": "バグがある製品をリリースするより、慎重策を取るべきだ。", "D": "慎重である"}},
252: {"nativeDefinition": "In a difficult situation with no good options.", "japaneseMeaning": "板挟み、ジレンマ", "etymology": "between a rock and a hard place（岩と堅い場所の間）が比喩的に板挟みを表す。", "examples": {"B": "今板挟みだ。親は地元にいてほしいと言うし、彼女は海外に行きたがっている。", "C": "板挟みだ。残業したら彼女に怒られるし、しないと上司に怒られる。", "D": "ジレンマにある"}},
253: {"nativeDefinition": "To manage to survive difficult circumstances.", "japaneseMeaning": "（困難に）耐え抜く、何とかやりくりする", "etymology": "keep one's head above water（水面から頭を出す）が比喩的に困難を凌ぐことを表す。", "examples": {"B": "最近買い物する時間がない。何とかやりくりしようとしている。", "C": "いくつか手伝ってくれる？何とかやりくりするのに苦労している。", "D": "困難に屈しない"}},
254: {"nativeDefinition": "Unsteady; not confident or reliable.", "japaneseMeaning": "不安定な、自信がない", "etymology": "shaky（揺れる）が比喩的に不安定・自信がないことを表す。", "examples": {"B": "英語はまだ所々不安定だけど、だんだん良くなっている。", "C": "初めての3Dアニメーションだから少し不安定だけど、練習すれば良くなる。", "D": "弱い"}},
255: {"nativeDefinition": "To reveal shocking or unexpected news.", "japaneseMeaning": "爆弾発言をする、衝撃的なことを明かす", "etymology": "drop a bombshell（爆弾を落とす）が比喩的に衝撃的な発表を表す。", "examples": {"B": "ブレットが今朝爆弾発言をした。明日会社を辞めるらしい。", "C": "母が昨日爆弾発言をした。知らない兄がいるらしい。", "D": "予想外のニュースを明かす"}},
256: {"nativeDefinition": "For the record; just so you know.", "japaneseMeaning": "念のため言っておくと、記録のために", "etymology": "for the record（記録のために）で、はっきり言っておく前置き。", "examples": {"B": "紹介した友達は気に入った？念のため言っておくと、彼は超いい奴だよ。", "C": "フェイスブックでこの人と話すのは楽しい。念のため言っておくと、直接会ったことはない。", "D": "知っておいてほしい"}},
257: {"nativeDefinition": "To accumulate a large supply of something.", "japaneseMeaning": "（何かを）蓄えておく、ストックする", "etymology": "stockpile（備蓄）で、大量に蓄えることを表す。", "examples": {"B": "ここ数年良いワインを蓄えてきた。ゆっくり楽しみたい。", "C": "政府は企業に利益の蓄積を避けるよう圧力をかけている。", "D": "何かを備蓄する"}},
258: {"nativeDefinition": "To judge based only on outward appearance.", "japaneseMeaning": "見た目で判断する", "etymology": "don't judge a book by its cover（表紙で本を判断するな）の故事から。", "examples": {"B": "見た目で判断するな。見た目は怖くても、実はいい人かもしれない。", "C": "また年齢確認？若く見えるけど、見た目で判断するな。", "D": "外見だけで判断する"}},
259: {"nativeDefinition": "Looking at the positive side of a situation.", "japaneseMeaning": "良い面を見れば", "etymology": "on a positive note で、ポジティブな面に目を向ける前置き。", "examples": {"B": "週末ずっと雨みたいだけど、良い面を見れば、洗濯はしなくて済む。", "C": "一週間残業で疲れたけど、良い面を見れば、3連休がある。", "D": "ポジティブな面を見る"}},
260: {"nativeDefinition": "To leave; or to become very successful.", "japaneseMeaning": "出発する、大成功する", "etymology": "take off（離陸する）が出発や成功の両方を表す。", "examples": {"B": "5分で出発する。子どもを学校から迎えに行かなきゃ。", "C": "トヨタの新車は大成功している。発売2ヶ月で売り切れた。", "D": "去る。うまくいく。"}},
261: {"nativeDefinition": "To be assigned an undesirable task by chance.", "japaneseMeaning": "不運な役回りを引く", "etymology": "draw the short straw（短いわらを引く）が比喩的に不運な役割を表す。", "examples": {"B": "今回は本当に不運な役回りを引いた。3日連続夜勤だ。", "C": "意地悪な面接官との面接を引いてしまった。最悪だった。", "D": "不運である"}},
262: {"nativeDefinition": "To vent frustration on someone innocent.", "japaneseMeaning": "（人に）八つ当たりする", "etymology": "take it out on sb（～にぶちまける）が比喩的に八つ当たりを表す。", "examples": {"B": "従業員に八つ当たりするのはやめて。職場の雰囲気が悪くなる。", "C": "ご迷惑をおかけして申し訳ありませんが、配達遅延は私の管理外です。八つ当たりしないでください。", "D": "誰かに感情をぶつける"}},
263: {"nativeDefinition": "To examine something in great detail.", "japaneseMeaning": "（～を）綿密に調べる", "etymology": "fine-tooth comb（細かい歯の櫛）で、細部まで調べることを表す。", "examples": {"B": "提出後は変更できないから、レポートを綿密に確認して。", "C": "ジョンが財務諸表を綿密に調べている。", "D": "詳細に検討する"}},
264: {"nativeDefinition": "To have complete freedom to act.", "japaneseMeaning": "自由裁量権を持つ", "etymology": "free rein（自由な手綱）が比喩的に完全な自由を表す。", "examples": {"B": "美容師に髪の色は自由に決めてもらった。信頼しているから。", "C": "妻には食事の場所を自由に決めてもらっている。僕は何でもいいから。", "D": "完全な自由を持つ"}},
265: {"nativeDefinition": "To delay or postpone something.", "japaneseMeaning": "（～を）延期する、控える", "etymology": "hold off on で、延期・控えることを表す。", "examples": {"B": "質問を控えるな。バカな質問なんてない。", "C": "ピーターにパイの焼き始めを控えてもらえる？必要かどうかまだわからない。", "D": "何かを延期する"}},
266: {"nativeDefinition": "Uninformed; not knowing what's happening.", "japaneseMeaning": "知らされていない、暗闇の中", "etymology": "in the dark（暗闇の中）が比喩的に情報を与えられていないことを表す。", "examples": {"B": "彼女がなぜ2つのLINEアカウントを持っているのか知らされていない。不安になってきた。", "C": "政府は首相の健康状態について国民を知らせていない。", "D": "情報を与えられていない"}},
267: {"nativeDefinition": "To analyze something in detail.", "japaneseMeaning": "（概念などを）詳しく分析する", "etymology": "unpack（荷解きする）が比喩的に詳しく分析することを表す。", "examples": {"B": "ベーシックインカムは分析すべきことがたくさんある魅力的なテーマだ。", "C": "この概念を詳しく分析させて。かなり複雑だ。", "D": "何かを分解して分析する"}},
268: {"nativeDefinition": "Wait; hold on.", "japaneseMeaning": "待って、ちょっと待った", "etymology": "hold your horses（馬を止めろ）が比喩的に待てという表現。", "examples": {"B": "全部株に投資しようとしていたけど、ファイナンシャルアドバイザーに待てと言われた。", "C": "え、待って。同じ高校だったの？話したことないのに。", "D": "待つ"}},
269: {"nativeDefinition": "To get an unpleasant task done quickly.", "japaneseMeaning": "（嫌なことを）さっさと終わらせる", "etymology": "get it over with で、嫌なことを早く終わらせることを表す。", "examples": {"B": "さっさと親知らずを抜くことにした。ずっと悩まされていたから。", "C": "あの人と話してさっさと終わらせよう。もう会たくない。", "D": "早く終わらせる"}},
270: {"nativeDefinition": "Convinced about something.", "japaneseMeaning": "（～に）納得している、賛成している", "etymology": "sold on（売られた）が比喩的に納得・賛成を表す。", "examples": {"B": "必要なスキルと知識はあるけど、性格にはまだ納得していない。", "C": "このアイデアにはまだ納得していない。初心者にとって可能なのか？", "D": "何かに納得している"}},
271: {"nativeDefinition": "To fail under pressure.", "japaneseMeaning": "（プレッシャーで）失敗する、萎える", "etymology": "choke（息が詰まる）が比喩的にプレッシャーで失敗することを表す。", "examples": {"B": "ゴール直前でいつも萎えて、レースに勝てない。", "C": "クリスティアーノはチャンスがあっても萎えないからたくさんゴールを決める。", "D": "プレッシャーに屈する"}},
272: {"nativeDefinition": "Fear of missing out on something.", "japaneseMeaning": "取り残される恐怖", "etymology": "FOMO（Fear Of Missing Out）の略。見逃す恐怖を表す現代用語。", "examples": {"B": "研究によると、取り残される恐怖がソーシャルメディア中毒の最大の原因の一つだ。", "C": "パーティーに行きたくなかったけど、取り残される恐怖で結局行った。", "D": "見逃すことへの恐怖"}},
273: {"nativeDefinition": "To change one's mind about something.", "japaneseMeaning": "考えを変える", "etymology": "change of heart（心の変化）で、考えを変えることを表す。", "examples": {"B": "今さら考えを変えても遅い。もうデザイナーに何を作るか伝えた。", "C": "さっき考えを変えて、仕事を辞めて世界一周することにした。", "D": "心変わりする"}},
274: {"nativeDefinition": "To try to gain favor by being overly flattering.", "japaneseMeaning": "（人に）媚びる、ご機嫌取りをする", "etymology": "suck up to（吸い上げる）が比喩的に媚びることを表す。", "examples": {"B": "ネオジが上司に媚びているのは明らかだ。他の人にはそんなに親切じゃない。", "C": "要するに、その記事は日本の首相が外国の指導者に媚びるのが好きだと言っていた。", "D": "自分を売り込む"}},
275: {"nativeDefinition": "A simple solution to a complex problem.", "japaneseMeaning": "特効薬、簡単な解決策", "etymology": "silver bullet（銀の弾丸）が狼男伝説から転じ、特効薬を表す。", "examples": {"B": "地球温暖化を解決する特効薬はない。お金をばらまくだけではダメだ。", "C": "日本の人口減少に特効薬はない。複雑な問題だ。", "D": "魔法のような解決策"}},
276: {"nativeDefinition": "Someone who loves reading books.", "japaneseMeaning": "本の虫、読書好き", "etymology": "bookworm（本の虫）で、読書好きな人を表す。", "examples": {"B": "読書好きの友人は最高だ。文学の知識を披露するのが好きだ。", "C": "この電子書籍リーダーは読書好きの彼女への最高の誕生日プレゼントだ。", "D": "本が好きな人"}},
277: {"nativeDefinition": "To use maximum effort or resources.", "japaneseMeaning": "全力を尽くす、全てを賭ける", "etymology": "go for broke（破産するまで）が比喩的に全力投球を表す。", "examples": {"B": "来週までに宿題を終わらせるために全力を尽くす。", "C": "このプロジェクトは重要だから、全力を尽くさなきゃいけない。", "D": "最大限の努力や資源を使う"}},
278: {"nativeDefinition": "Something one is particularly good at.", "japaneseMeaning": "得意分野、強み", "etymology": "strong suit（強いスート）が比喩的に得意分野を表す。", "examples": {"B": "文法は聞かないで。僕の得意分野じゃない。", "C": "会計は本当に苦手だ。全然得意分野じゃない。", "D": "強み"}},
279: {"nativeDefinition": "To ask someone for advice or information.", "japaneseMeaning": "（人に）意見を聞く、知恵を借りる", "etymology": "pick one's brain（脳を摘む）が比喩的に知恵を借りることを表す。", "examples": {"B": "この数学の問題について意見を聞いてもいい？君は専門家だから。", "C": "コンサル会社に頼まない方がいい。意見を聞くだけで高額請求される。", "D": "誰かに助言を求める"}},
280: {"nativeDefinition": "Perfect; done exactly as it should be.", "japaneseMeaning": "教科書通りの、完璧な", "etymology": "textbook（教科書）が形容詞的に模範的・完璧を表す。", "examples": {"B": "あれはまさに教科書通りのフリーキックだった。彼は本当に上手い。", "C": "あのスラムダンクは教科書通りだった。", "D": "完璧"}},
281: {"nativeDefinition": "Everyone has their own preferences.", "japaneseMeaning": "人それぞれ、十人十色", "etymology": "to each their own（それぞれに自分のもの）で、人それぞれを表す。", "examples": {"B": "コリアンダーが嫌い？僕にとっては最高のハーブだけど、まあ人それぞれだね。", "C": "同じ会社に10年以上働きたくないけど、人それぞれだよね。", "D": "人にはそれぞれ好みがある"}},
282: {"nativeDefinition": "To avoid humiliation or embarrassment.", "japaneseMeaning": "面子を保つ", "etymology": "save face（顔を保つ）が東洋的な概念を英語に取り入れた表現。", "examples": {"B": "クリスが面子を保つのはもう遅い。みんな失敗したことを知っている。", "C": "ディナーに顔を出して面子を保つ必要がある。前回は欠席した。", "D": "恥を避ける"}},
283: {"nativeDefinition": "To support something.", "japaneseMeaning": "（何かを）支持する", "etymology": "get behind（後ろについて）が比喩的に支持することを表す。", "examples": {"B": "今夜はチームをしっかり支持しよう。応援されているとよくプレーする。", "C": "ジェームズがこのプロジェクトを支持してくれているのは嬉しい。ずっと熱心に取り組んでいる。", "D": "何かを支持する"}},
284: {"nativeDefinition": "Given the current situation.", "japaneseMeaning": "現状では、今のところ", "etymology": "as it stands（現状のまま）で、今の状況ではを表す。", "examples": {"B": "現状ではランチに行けない。忙しそうだ。", "C": "現状では来年新しい車は買えない。", "D": "現在の状況を考えると"}},
285: {"nativeDefinition": "To expand one's knowledge and experiences.", "japaneseMeaning": "視野を広げる", "etymology": "broaden horizons（地平線を広げる）が比喩的に視野を広げることを表す。", "examples": {"B": "留学して視野を広げるべきだ。", "C": "大学は様々な背景の人と出会い、視野を広げる素晴らしい機会だ。", "D": "見解を広げる"}},
286: {"nativeDefinition": "Unable to control one's behavior.", "japaneseMeaning": "（自分を）抑えられない", "etymology": "can't help oneself（自分を助けられない）で、自制できないことを表す。", "examples": {"B": "デザートの前では自分を抑えられない。大好きなんだ。", "C": "メーガンは自分を抑えられない。うまくいかないことはすべて批判しなきゃいけない。", "D": "自分をコントロールできない"}},
287: {"nativeDefinition": "Extremely happy.", "japaneseMeaning": "舞い上がるほど嬉しい", "etymology": "over the moon（月の上）が比喩的に最高の喜びを表す。", "examples": {"B": "クリスマスに新しいスマホをもらえて舞い上がるほど嬉しい。期待していなかった。", "C": "昨夜一緒に過ごせて本当に舞い上がるほど嬉しかった。", "D": "とても幸せ"}},
288: {"nativeDefinition": "Please tell me again; refresh my memory.", "japaneseMeaning": "もう一度教えて、思い出させて", "etymology": "remind me again で、再度教えてほしいという依頼。", "examples": {"B": "もう一度教えて、ここから家にどう帰るんだっけ？酔っ払ってる。", "C": "昨日の授業で何をやったかもう一度教えてくれる？実は寝ていた。", "D": "記憶を更新する"}},
289: {"nativeDefinition": "To progress through something with difficulty.", "japaneseMeaning": "（何かを）なんとか進める、よろめきながら進む", "etymology": "stumble through（つまずきながら）が比喩的に困難を伴い進むことを表す。", "examples": {"B": "フィルはスピーチをよろめきながら進めた。練習していなかったのが明らかだった。", "C": "日本語を学ぶのにワクワクしていたけど、よろめきながら進んだ。思ったより難しかった。", "D": "困難を伴いながら進む"}},
290: {"nativeDefinition": "Feeling nervous and anxious.", "japaneseMeaning": "パニック気味の、不安な", "etymology": "panicky（パニックの）で、不安でパニックになりそうなことを表す。", "examples": {"B": "サムは人前でプレゼンすると少しパニック気味になる。", "C": "仕事の不安定さで少しパニック気味だ。眠れない。", "D": "神経質で不安"}},
291: {"nativeDefinition": "Unfair and cruel.", "japaneseMeaning": "卑劣な、フェアじゃない", "etymology": "below the belt（ベルトの下）がボクシングから転じ、卑劣なことを表す。", "examples": {"B": "「いつ結婚するの？」と聞くのは卑劣だ。", "C": "昔のミスについて謝ったのに、みんなの前で蒸し返すのは卑劣だ。", "D": "残酷で不公平"}},
292: {"nativeDefinition": "Extremely rare or unique.", "japaneseMeaning": "百万に一人、非常に稀", "etymology": "one in a million（100万人に1人）が比喩的に非常に稀を表す。", "examples": {"B": "彼女が百万に一人で他にいないなんて本気で思ってるの？まさか。", "C": "この新曲がヒットする確率は百万に一つだ。", "D": "独特で、ありそうにない"}},
293: {"nativeDefinition": "A memorable or intense experience.", "japaneseMeaning": "（忘れられない）体験", "etymology": "an experience で、印象的な体験を表す。", "examples": {"B": "高校生のとき、よくマクドナルドで遅くまで勉強していた。忘れられない体験だった。", "C": "バンジージャンプはどうだった？体験だったけど、もう二度とやらない。", "D": "興味深い体験"}},
294: {"nativeDefinition": "To accomplish two things with one action.", "japaneseMeaning": "一石二鳥", "etymology": "kill two birds with one stone（一つの石で二羽の鳥を殺す）の故事から。", "examples": {"B": "サイクリングは一石二鳥だ。健康維持と移動が同時にできる。", "C": "トレッドミルで読書するのが好きだ。一石二鳥だ。", "D": "一つの行動で二つのことを達成する"}},
295: {"nativeDefinition": "To cancel or stop something.", "japaneseMeaning": "（何かを）中止する、打ち切る", "etymology": "pull the plug（プラグを抜く）が比喩的に中止することを表す。", "examples": {"B": "あのテレビ番組が打ち切られたなんて信じられない。まだ始まったばかりなのに。", "C": "ごめん、今日のランチは中止する。少し具合が悪い。", "D": "キャンセルする"}},
296: {"nativeDefinition": "Past events that are no longer worth worrying about.", "japaneseMeaning": "水に流す、過ぎたこと", "etymology": "water under the bridge（橋の下の水）が比喩的に過ぎ去ったことを表す。", "examples": {"B": "もう怒っていない。ずっと前のことだ。水に流した。", "C": "6ヶ月前に別れた。もう水に流した。", "D": "すべて過去のこと"}},
297: {"nativeDefinition": "The most important or dominant person.", "japaneseMeaning": "トップ、最有力者", "etymology": "top dog（一番の犬）が比喩的にトップの人を表す。", "examples": {"B": "ニックをあまり怒らせない方がいい。ここではトップだから。", "C": "彼女がトップだと思っているけど、誰も彼女の言うことを聞いていない。", "D": "最も重要な人"}},
298: {"nativeDefinition": "No news probably means nothing bad has happened.", "japaneseMeaning": "便りがないのは良い知らせ", "etymology": "no news is good news で、連絡がなければ悪いことはないという意味。", "examples": {"B": "クレジットカード会社から何も聞いていない。便りがないのは良い知らせだよね。", "C": "CEOはリストラについて何も言っていない。便りがないのは良い知らせだと思う。", "D": "何も聞かないことは悪いことが起きていないことを示す"}},
299: {"nativeDefinition": "To be stared at by people.", "japaneseMeaning": "人にジロジロ見られる", "etymology": "get looks from people で、人々の視線を感じることを表す。", "examples": {"B": "日本で英語を話すと、人にジロジロ見られるかもしれないけど、最高の練習だ。", "C": "そのTシャツを着るの本当にいい？人にジロジロ見られるよ。", "D": "人に見つめられる"}},
300: {"nativeDefinition": "A certain success; a sure thing.", "japaneseMeaning": "確実な成功、決まり", "etymology": "slam dunk（スラムダンク）が比喩的に確実な成功を表す。", "examples": {"B": "プロポーズが受け入れられるのは確実だと思っていたけど、断られた。", "C": "面接官がすごく気に入ってくれたから、この仕事は確実だと思う。", "D": "確実な成功"}},
}
